const response = $input.first().json;
const text = response?.result?.content?.[0]?.text;
if (!text) {
  throw new Error('Bilig MCP did not return MCP text content.');
}
const proof = JSON.parse(text);
const displayValue = proof?.after?.displayValue;
const formula = proof?.after?.formula;
const restoredMatchesAfter = proof?.checks?.restoredMatchesAfter === true;
if (formula !== '=B2*B3') {
  throw new Error('Unexpected formula readback: ' + String(formula));
}
if (displayValue !== '5') {
  throw new Error('Unexpected calculated value: ' + String(displayValue));
}
if (!restoredMatchesAfter) {
  throw new Error('Bilig MCP did not prove restored readback.');
}
return [{
  json: {
    summary: 'Bilig WorkPaper calculated =B2*B3 as 5 and proved restored readback.',
    editedCell: proof.editedCell,
    formula,
    displayValue,
    restoredMatchesAfter,
    github: 'https://github.com/proompteng/bilig',
    docs: 'https://proompteng.github.io/bilig/mcp-workpaper-tool-server.html',
    mcpRegistry: 'https://registry.modelcontextprotocol.io/v0.1/servers?search=io.github.proompteng%2Fbilig-workpaper',
    proof
  }
}];
